#!/usr/bin/env python3
"""Convert Claude Code .jsonl session logs into readable Markdown transcripts."""
import json
import os
import sys
from datetime import datetime, timezone

SRC_DIR = "/Users/marek/.claude/projects/-Users-marek-2026-IRON-daktela"
OUT_DIR = "/Users/marek/2026/IRON/daktela/konverzacie"

os.makedirs(OUT_DIR, exist_ok=True)
os.makedirs(os.path.join(OUT_DIR, "raw"), exist_ok=True)


def fmt_ts(ts):
    if not ts:
        return ""
    try:
        dt = datetime.fromisoformat(ts.replace("Z", "+00:00")).astimezone()
        return dt.strftime("%Y-%m-%d %H:%M:%S")
    except Exception:
        return ts


def render_content(content):
    """Render a message 'content' (str or list of blocks) to markdown."""
    out = []
    if isinstance(content, str):
        return content.strip()
    if not isinstance(content, list):
        return str(content)
    for block in content:
        if not isinstance(block, dict):
            out.append(str(block))
            continue
        btype = block.get("type")
        if btype == "text":
            out.append(block.get("text", "").strip())
        elif btype == "thinking":
            txt = block.get("thinking", "").strip()
            if txt:
                out.append(f"> 🧠 *(thinking)*\n>\n" + "\n".join("> " + l for l in txt.splitlines()))
        elif btype == "tool_use":
            name = block.get("name", "?")
            inp = block.get("input", {})
            try:
                inp_str = json.dumps(inp, ensure_ascii=False, indent=2)
            except Exception:
                inp_str = str(inp)
            if len(inp_str) > 4000:
                inp_str = inp_str[:4000] + "\n… (truncated)"
            out.append(f"**🔧 Tool call: `{name}`**\n```json\n{inp_str}\n```")
        elif btype == "tool_result":
            c = block.get("content", "")
            if isinstance(c, list):
                c = "\n".join(
                    b.get("text", "") if isinstance(b, dict) else str(b) for b in c
                )
            c = str(c).strip()
            if len(c) > 3000:
                c = c[:3000] + "\n… (truncated)"
            out.append(f"**📄 Tool result:**\n```\n{c}\n```")
        elif btype == "image":
            out.append("*(image omitted)*")
        else:
            out.append(f"*({btype} block)*")
    return "\n\n".join(p for p in out if p)


def role_label(role, mtype):
    if role == "user":
        return "🧑 User"
    if role == "assistant":
        return "🤖 Claude"
    if mtype == "system":
        return "⚙️ System"
    return role or mtype or "?"


def convert(path):
    rows = []
    with open(path, "r", encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            try:
                rows.append(json.loads(line))
            except Exception:
                continue

    session_id = os.path.splitext(os.path.basename(path))[0]
    # collect meta
    first_ts = last_ts = None
    git_branch = cwd = version = None
    msgs = []
    for r in rows:
        ts = r.get("timestamp")
        if ts:
            if first_ts is None:
                first_ts = ts
            last_ts = ts
        git_branch = r.get("gitBranch", git_branch)
        cwd = r.get("cwd", cwd)
        version = r.get("version", version)
        rtype = r.get("type")
        if rtype in ("user", "assistant"):
            msg = r.get("message", {})
            role = msg.get("role", rtype)
            content = msg.get("content", "")
            rendered = render_content(content)
            if rendered:
                msgs.append((fmt_ts(ts), role_label(role, rtype), rendered))
        elif rtype == "system" and r.get("subtype") == "local_command":
            content = r.get("content", "")
            if content:
                msgs.append((fmt_ts(ts), "⚙️ System", content.strip()))

    lines = []
    lines.append(f"# Conversation — {session_id}")
    lines.append("")
    lines.append(f"- **Session ID:** `{session_id}`")
    lines.append(f"- **Start:** {fmt_ts(first_ts)}")
    lines.append(f"- **End:** {fmt_ts(last_ts)}")
    if git_branch:
        lines.append(f"- **Git branch:** `{git_branch}`")
    if cwd:
        lines.append(f"- **Working dir:** `{cwd}`")
    if version:
        lines.append(f"- **Claude Code version:** {version}")
    lines.append(f"- **Messages:** {len(msgs)}")
    lines.append("")
    lines.append("---")
    lines.append("")
    for ts, who, body in msgs:
        header = f"### {who}"
        if ts:
            header += f"  ·  _{ts}_"
        lines.append(header)
        lines.append("")
        lines.append(body)
        lines.append("")
        lines.append("---")
        lines.append("")

    out_name = f"{fmt_ts(first_ts)[:10] or 'session'}__{session_id[:8]}.md"
    out_path = os.path.join(OUT_DIR, out_name)
    with open(out_path, "w", encoding="utf-8") as f:
        f.write("\n".join(lines))
    return out_name, first_ts, last_ts, len(msgs)


def main():
    sessions = sorted(
        f for f in os.listdir(SRC_DIR) if f.endswith(".jsonl")
    )
    index = []
    for fn in sessions:
        src = os.path.join(SRC_DIR, fn)
        out_name, first_ts, last_ts, n = convert(src)
        # copy raw
        raw_dst = os.path.join(OUT_DIR, "raw", fn)
        with open(src, "rb") as a, open(raw_dst, "wb") as b:
            b.write(a.read())
        index.append((fmt_ts(first_ts), out_name, n))
        print(f"  {out_name}  ({n} messages)")

    # build index
    idx_lines = ["# Conversation archive — Daktela project", "",
                 f"_Exported {datetime.now().strftime('%Y-%m-%d %H:%M')}_", "",
                 "Readable Markdown transcripts of all Claude Code sessions for this project. "
                 "Raw `.jsonl` session logs are in [`raw/`](raw/).", "",
                 "| Date | Transcript | Messages |",
                 "|------|------------|----------|"]
    for first_ts, out_name, n in sorted(index):
        idx_lines.append(f"| {first_ts[:10] if first_ts else '—'} | [{out_name}]({out_name}) | {n} |")
    with open(os.path.join(OUT_DIR, "README.md"), "w", encoding="utf-8") as f:
        f.write("\n".join(idx_lines) + "\n")
    print(f"\nWrote {len(sessions)} transcripts + index to {OUT_DIR}")


if __name__ == "__main__":
    main()

