"""Convert Claude Code .jsonl session logs into clean, readable Markdown transcripts.

Goal: show what the USER wrote and what CLAUDE said/did — not the raw tool plumbing.
- User typed messages: shown in full (system-reminder / context dumps stripped).
- Claude text: shown in full.
- Tool calls: collapsed to a one-line summary (e.g. "📖 Read `file`").
- Tool RESULTS and internal "thinking": omitted (kept only in raw/*.jsonl).
"""
import json
import os
import re
from datetime import datetime

SRC_DIR = "/Users/marek/.claude/projects/-Users-marek-2026-IRON-daktela"
OUT_DIR = "/Users/marek/2026/IRON/daktela/konverzacie"
PROJ = "/Users/marek/2026/IRON/daktela/"

os.makedirs(OUT_DIR, exist_ok=True)
os.makedirs(os.path.join(OUT_DIR, "raw"), exist_ok=True)


def fmt_ts(ts):
    if not ts:
        return ""
    try:
        dt = datetime.fromisoformat(ts.replace("Z", "+00:00")).astimezone()
        return dt.strftime("%Y-%m-%d %H:%M")
    except Exception:
        return ts


def rel(p):
    if isinstance(p, str):
        return p.replace(PROJ, "")
    return p


def clean_user_text(text):
    """Strip harness noise from a user-typed message."""
    # Remove system-reminder blocks (context dumps, selection notes, etc.)
    text = re.sub(r"<system-reminder>.*?</system-reminder>", "", text, flags=re.DOTALL)
    # Command wrappers -> compact note
    text = re.sub(r"<command-message>.*?</command-message>", "", text, flags=re.DOTALL)
    text = re.sub(r"<command-args>.*?</command-args>", "", text, flags=re.DOTALL)
    text = re.sub(r"<command-name>(.*?)</command-name>", r"⚙️ command: \1", text, flags=re.DOTALL)
    text = re.sub(r"<local-command-stdout>(.*?)</local-command-stdout>", r"↳ \1", text, flags=re.DOTALL)
    # Drop the "selected lines" IDE context that has no real prompt
    text = re.sub(r"The user selected the lines.*", "", text, flags=re.DOTALL)
    return text.strip()


def summarize_tool(name, inp):
    if not isinstance(inp, dict):
        return f"🔧 {name}"
    if name == "Read":
        return f"📖 Read `{rel(inp.get('file_path', ''))}`"
    if name == "Write":
        return f"📝 Write `{rel(inp.get('file_path', ''))}`"
    if name in ("Edit", "NotebookEdit"):
        return f"✏️ Edit `{rel(inp.get('file_path', ''))}`"
    if name == "Bash":
        cmd = (inp.get("command", "") or "").strip().splitlines()
        cmd = cmd[0] if cmd else ""
        if len(cmd) > 120:
            cmd = cmd[:120] + "…"
        desc = inp.get("description", "")
        return f"💻 Bash: `{cmd}`" + (f"  — _{desc}_" if desc else "")
    if name == "Grep":
        return f"🔍 Grep `{inp.get('pattern', '')}`"
    if name == "Glob":
        return f"🔍 Glob `{inp.get('pattern', '')}`"
    if name == "TodoWrite":
        return "✅ Updated todo list"
    if name in ("Task", "Agent"):
        return f"🤝 Subagent: {inp.get('description', inp.get('subagent_type', ''))}"
    if name == "WebFetch":
        return f"🌐 WebFetch {inp.get('url', '')}"
    if name == "WebSearch":
        return f"🌐 WebSearch \"{inp.get('query', '')}\""
    if name == "Skill":
        return f"🧩 Skill: /{inp.get('skill', '')} {inp.get('args', '')}".strip()
    return f"🔧 {name}"


def render_assistant(content):
    """Return (text_parts, tool_lines) for an assistant message."""
    texts, tools = [], []
    if isinstance(content, str):
        if content.strip():
            texts.append(content.strip())
        return texts, tools
    for block in content if isinstance(content, list) else []:
        if not isinstance(block, dict):
            continue
        bt = block.get("type")
        if bt == "text":
            t = block.get("text", "").strip()
            if t:
                texts.append(t)
        elif bt == "tool_use":
            tools.append(summarize_tool(block.get("name", "?"), block.get("input", {})))
        # thinking / others: skipped
    return texts, tools


def user_is_real(content):
    """True if this user row is a typed message (not a tool_result carrier)."""
    if isinstance(content, str):
        return True
    if isinstance(content, list):
        for b in content:
            if isinstance(b, dict) and b.get("type") == "text":
                return True
        return False
    return False


def user_text(content):
    if isinstance(content, str):
        return content
    parts = []
    for b in content if isinstance(content, list) else []:
        if isinstance(b, dict) and b.get("type") == "text":
            parts.append(b.get("text", ""))
    return "\n\n".join(parts)


