def render_content(content):
    """Render a message 'content' (str or list of blocks) to markdown."""
    out = []
    if isinstance(content, str):
        return content.strip()
    if not isinstance(content, list):
        return str(content)
    for block in content:
        if not isinstance(block, dict):
            out.append(str(block))
            continue
        btype = block.get("type")
        if btype == "text":
            out.append(block.get("text", "").strip())
        elif btype == "thinking":
            txt = block.get("thinking", "").strip()
            if txt:
                out.append(f"> 🧠 *(thinking)*\n>\n" + "\n".join("> " + l for l in txt.splitlines()))
        elif btype == "tool_use":
            name = block.get("name", "?")
            inp = block.get("input", {})
            try:
                inp_str = json.dumps(inp, ensure_ascii=False, indent=2)
            except Exception:
                inp_str = str(inp)
            if len(inp_str) > 4000:
                inp_str = inp_str[:4000] + "\n… (truncated)"
            out.append(f"**🔧 Tool call: `{name}`**\n```json\n{inp_str}\n```")
        elif btype == "tool_result":
            c = block.get("content", "")
            if isinstance(c, list):
                c = "\n".join(
                    b.get("text", "") if isinstance(b, dict) else str(b) for b in c
                )
            c = str(c).strip()
            if len(c) > 3000:
                c = c[:3000] + "\n… (truncated)"
            out.append(f"**📄 Tool result:**\n```\n{c}\n```")
        elif btype == "image":
            out.append("*(image omitted)*")
        else:
            out.append(f"*({btype} block)*")
    return "\n\n".join(p for p in out if p)


def role_label(role, mtype):
    if role == "user":
        return "🧑 User"
    if role == "assistant":
        return "🤖 Claude"
    if mtype == "system":
        return "⚙️ System"
